#include <bits/stdc++.h>
using namespace std;

typedef long long ll;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;
    vector<pair<ll, int>> cows(N);
    for (int i = 0; i < N; i++) {
        cin >> cows[i].first >> cows[i].second;
    }

    // Sort by position
    sort(cows.begin(), cows.end());

    // Count distinct breeds
    unordered_set<int> breeds_set;
    for (auto &c : cows) breeds_set.insert(c.second);
    int K = (int)breeds_set.size();

    // Sliding window to find minimum range covering all K breeds
    unordered_map<int, int> cnt;
    int distinct = 0;
    ll ans = LLONG_MAX;
    int r = 0;

    for (int l = 0; l < N; l++) {
        while (r < N && distinct < K) {
            int b = cows[r].second;
            if (cnt[b] == 0) distinct++;
            cnt[b]++;
            r++;
        }
        if (distinct == K) {
            ll cost = cows[r - 1].first - cows[l].first;
            ans = min(ans, cost);
        }
        // Move left pointer
        int b = cows[l].second;
        cnt[b]--;
        if (cnt[b] == 0) distinct--;
    }

    if (ans == LLONG_MAX) cout << -1 << "\n";
    else cout << ans << "\n";

    return 0;
}
